:root {
  /* Color palette */
  --color-primary-500: #00AAF0;
  --color-primary-600: #00B5E2;
  --color-accent-500: #0088CC;

  --color-secondary-700: #333333;
  --color-secondary-800: #444444;

  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F5F5F5;
  --color-neutral-100: #E5E5E5;
  --color-neutral-200: #CCCCCC;
  --color-neutral-300: #999999;

  --color-success: #2ECC71;
  --color-error: #E74C3C;
  --color-warning: #F1C40F;
  --color-info: #3498DB;

  --color-text-main: #333333;
  --color-text-muted: #666666;
  --color-header-border: #E5E5E5;

  /* Typography */
  --font-heading: 'DM Sans', 'Helvetica', 'Arial', sans-serif;
  --font-body: 'Source Sans 3', 'Helvetica', 'Arial', sans-serif;
  --font-code: 'Source Code Pro', Menlo, Monaco, monospace;

  --font-size-h1: 32px;
  --font-size-h2: 22px;
  --font-size-h3: 18px;
  --font-size-body: 15px;
  --font-size-small: 13px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --layout-max-width: 1120px;
  --header-height: 72px;
}

/* Reset and global styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-text-main);
  background-color: var(--color-neutral-000);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-accent-500);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

ul {
  margin: 0;
  padding: 0;
}

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

h1,
h2,
h3,
h4,
h5,
h6 {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-weight: 700;
  color: #000000;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin: 0 0 var(--space-3);
}

small {
  font-size: var(--font-size-small);
}

/* Header */

.site-header {
  background-color: var(--color-neutral-000);
  border-bottom: 1px solid var(--color-header-border);
}

.header-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height);
}

.menu-toggle,
.search-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: #000000;
  font-family: var(--font-heading);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-size: var(--font-size-small);
}

.menu-toggle {
  gap: var(--space-2);
}

.menu-label {
  display: inline-block;
}

.menu-icon {
  display: inline-flex;
  flex-direction: column;
  justify-content: center;
}

.menu-icon span {
  width: 22px;
  height: 2px;
  background-color: #000000;
  margin: 2px 0;
}

.site-logo {
  flex: 1 1 auto;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
}

.site-logo a {
  display: inline-flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-decoration: none;
}

.logo-boat {
  width: 120px;
  height: 20px;
  border-bottom: 3px solid #000000;
  border-radius: 1px;
  margin-bottom: 4px;
}

.logo-text {
  font-family: var(--font-heading);
  font-size: 20px;
  font-weight: 500;
  color: var(--color-primary-500);
}

.logo-dotcom {
  font-size: 0.85em;
}

.search-toggle {
  min-width: 32px;
}

.search-icon {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 2px solid #000000;
  position: relative;
  display: inline-block;
}

.search-icon::after {
  content: '';
  position: absolute;
  width: 9px;
  height: 2px;
  background-color: #000000;
  right: -4px;
  bottom: 1px;
  transform: rotate(45deg);
}

/* Primary navigation (off-canvas on small screens, horizontal on large) */

.primary-nav {
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  width: 260px;
  background-color: var(--color-neutral-000);
  border-right: 1px solid var(--color-header-border);
  transform: translateX(-100%);
  transition: transform 200ms ease-out;
  z-index: 1000;
}

body.nav-open .primary-nav {
  transform: translateX(0);
}

.primary-nav-inner {
  padding: var(--space-6) var(--space-4);
}

.primary-nav-list {
  list-style: none;
}

.primary-nav-list li + li {
  margin-top: var(--space-3);
}

.primary-nav-list a {
  display: block;
  font-family: var(--font-heading);
  font-size: 15px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-secondary-700);
}

.primary-nav-list a:hover {
  color: var(--color-primary-500);
}

/* Layout for main content */

.site-body {
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

.site-main {
  min-height: 40vh;
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-header-border);
  background-color: var(--color-neutral-050);
  padding-top: var(--space-5);
  padding-bottom: var(--space-5);
  font-size: var(--font-size-small);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

.footer-brand {
  max-width: 260px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 18px;
  letter-spacing: 0.09em;
  text-transform: uppercase;
  color: var(--color-secondary-800);
  text-decoration: none;
}

.footer-logo:hover {
  color: var(--color-primary-500);
}

.footer-tagline {
  margin-top: var(--space-1);
  color: var(--color-neutral-300);
}

.footer-nav-list {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3) var(--space-4);
}

.footer-nav-list a {
  font-family: var(--font-heading);
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  color: var(--color-secondary-700);
  text-decoration: none;
}

.footer-nav-list a:hover {
  color: var(--color-primary-500);
}

.footer-meta {
  color: var(--color-neutral-300);
}

.footer-copy {
  margin: 0;
}

/* Button pattern (for use in page content) */

.btn {
  display: inline-block;
  padding: 12px 28px;
  background-color: var(--color-primary-500);
  color: var(--color-neutral-000);
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  text-align: center;
  border: none;
  text-decoration: none;
}

.btn:hover {
  background-color: var(--color-primary-600);
}

.btn:disabled {
  background-color: var(--color-neutral-200);
  color: var(--color-neutral-000);
}

/* Responsive adjustments */

@media (min-width: 768px) {
  .footer-inner {
    flex-direction: row;
    align-items: flex-start;
    justify-content: space-between;
  }
}

@media (min-width: 960px) {
  /* Make navigation visible and horizontal on larger screens */
  .primary-nav {
    position: static;
    transform: none;
    width: auto;
    border-right: none;
    border-top: 1px solid var(--color-header-border);
  }

  .primary-nav-inner {
    max-width: var(--layout-max-width);
    margin: 0 auto;
    padding: 0 var(--space-4);
  }

  .primary-nav-list {
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  .primary-nav-list li + li {
    margin-top: 0;
  }

  .menu-toggle {
    display: none;
  }
}
